mapper.select:
select p.id, p.source_product_name sourceProductName, p.product_factory_id productFactoryId, mpf.factory_name productFactoryName, p.source_product_code sourceProductCode, p.source_product_url sourceProductUrl, p.head_img_url headImgUrl, p.logistics_name logisticsName, p.freight_cost freightCost, p.dispatch_time dispatchTime, p.steady_status steadyStatus from product p LEFT JOIN mall_product_factory mpf on mpf.id = p.product_factory_id where p.is_deleted=0
and p.source_product_name like concat('%',#{productDto.sourceProductName},'%')
and p.source_product_code = #{productDto.sourceProductCode}
and p.product_factory_id = #{productDto.productFactoryId}
and p.steady_status = #{productDto.steadyStatus}
order by p.create_time desc
